import React from "react";
import Slider from "react-slick";

const HeroSlider = () => {
  const slides = [
    {
      id: 1,
      title: "Experience Pure Sound – Your Perfect Headphones Awaits!",
      subtitle: "Limited Time Offer 30% Off",
      button: "Buy now",
      image: "/images/slider1.jpg",
      bgColor: "#F5F7FF"
    },
    {
      id: 2,
      title: "Upgrade Your Gaming Setup with the Latest Tech",
      subtitle: "Save up to 20% this week",
      button: "Shop now",
      image: "/images/slider2.png",
      bgColor: "#FFF5F5"
    },
    {
      id: 3,
      title: "Smartphones That Define the Future",
      subtitle: "New arrivals in stock",
      button: "Explore",
      image: "/images/slider3.png",
      bgColor: "#F5FFF7"
    }
  ];

  const settings = {
    dots: true,
    infinite: true,
    autoplay: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    arrows: false
  };

  return (
    <div className="w-full">
      <Slider {...settings}>
        {slides.map((slide) => (
          <div key={slide.id}>
            <div
              className="flex items-center justify-between p-10 rounded-xl"
              style={{ backgroundColor: slide.bgColor }}
            >
              {/* Left Side Text */}
              <div className="max-w-lg">
                <p className="text-sm text-orange-500 font-bold">{slide.subtitle}</p>
                <h2 className="text-3xl font-bold mt-2">{slide.title}</h2>
                <button className="mt-4 px-6 py-2 bg-orange-500 text-white rounded-lg shadow">
                  {slide.button}
                </button>
              </div>

              {/* Right Side Image */}
              <div className="w-1/2 flex justify-center">
                <img src={slide.image} alt={slide.title} className="h-60 object-contain" />
              </div>
            </div>
          </div>
        ))}
      </Slider>
    </div>
  );
};

export default HeroSlider;
